import * as ex from "excalibur";

export class DebugHubScene extends ex.Scene {
  private static _loadPromise: Promise<void> | null = null;
  private overlay: HTMLDivElement | null = null;

  public async onActivate() {
    this.showLoading();
    try {
      await this.loadRhythmData();
      this.createUI();
    } catch (e) {
      console.error("Failed to load rhythm data:", e);
      this.showError();
    }
  }

  private showLoading() {
    this.removeUI();
    const container = document.createElement("div");
    container.id = "debug-menu-overlay";
    container.style.position = "fixed";
    container.style.inset = "0";
    container.style.backgroundColor = "#0f172a";
    container.style.color = "#e2e8f0";
    container.style.zIndex = "9999";
    container.style.display = "flex";
    container.style.alignItems = "center";
    container.style.justifyContent = "center";
    container.style.fontFamily = 'Outfit, "Noto Sans JP", sans-serif';
    container.textContent = "楽曲データを読み込み中...";
    document.body.appendChild(container);
    this.overlay = container;
  }

  private showError() {
    this.removeUI();
    const container = document.createElement("div");
    container.id = "debug-menu-overlay";
    container.style.position = "fixed";
    container.style.inset = "0";
    container.style.backgroundColor = "#0f172a";
    container.style.color = "#ef4444";
    container.style.zIndex = "9999";
    container.style.display = "flex";
    container.style.flexDirection = "column";
    container.style.alignItems = "center";
    container.style.justifyContent = "center";
    container.style.fontFamily = 'Outfit, "Noto Sans JP", sans-serif';
    container.textContent =
      "楽曲データの読み込みに失敗しました。(/devtools/rhythm_data.js が存在することを確認してください)";
    document.body.appendChild(container);
    this.overlay = container;
  }

  private loadRhythmData(): Promise<void> {
    if ("tracks" in window) return Promise.resolve();
    if (DebugHubScene._loadPromise) return DebugHubScene._loadPromise;

    DebugHubScene._loadPromise = new Promise((resolve, reject) => {
      if (document.querySelector('script[src="devtools/rhythm_data.js"]')) {
        resolve();
        return;
      }
      const script = document.createElement("script");
      script.src = "devtools/rhythm_data.js";
      script.onload = () => resolve();
      script.onerror = (e) => reject(e);
      document.body.appendChild(script);
    });
    return DebugHubScene._loadPromise;
  }

  public onDeactivate() {
    this.removeUI();
  }

  private createUI() {
    this.removeUI();

    // デバッグメニュー用のコンテナを作成
    const container = document.createElement("div");
    container.id = "debug-menu-overlay";
    container.style.position = "fixed";
    container.style.inset = "0";
    container.style.backgroundColor = "#0f172a";
    container.style.color = "#e2e8f0";
    container.style.zIndex = "9999";
    container.style.display = "flex";
    container.style.flexDirection = "column";
    container.style.alignItems = "center";
    container.style.justifyContent = "center";
    container.style.fontFamily = 'Outfit, "Noto Sans JP", sans-serif';
    container.style.padding = "2rem";

    // タイトル
    const title = document.createElement("h1");
    title.textContent = "Bard In Maghribal - 開発用デバッグメニュー";
    title.style.color = "#38bdf8";
    title.style.borderBottom = "2px solid #334155";
    title.style.paddingBottom = "0.5rem";
    title.style.marginBottom = "2rem";
    container.appendChild(title);

    // リスト
    const list = document.createElement("ul");
    list.style.listStyle = "none";
    list.style.padding = "0";
    list.style.display = "grid";
    list.style.gridTemplateColumns = "repeat(auto-fill, minmax(280px, 1fr))";
    list.style.gap = "1.5rem";
    list.style.width = "100%";
    list.style.maxWidth = "800px";

    const tools = [
      {
        title: "優美演奏テスター EX",
        desc: "優美属性ミニゲームの最新テスター（Excalibur版）",
        scene: "elegant-rhythm-tester",
      },
      {
        title: "勇猛ミニゲーム テスター EX",
        desc: "勇猛属性ミニゲームのテストプロトタイプ",
        scene: "brave-rhythm-tester",
      },
      {
        title: "VocalMP4 変換アセットテスター",
        desc: "MP4から変換されたMP3、WebP、および歌詞JSONの再生検証ツールを開きます",
        scene: "",
        isLink: true,
        url: "devtools/vocalmp4-player-tester.html"
      },
      {
        title: "ゲーム本編（タイトル画面）へ",
        desc: "デバッグメニューを終了してゲームタイトル画面に戻ります",
        scene: "title",
        isBack: true,
      },
    ];

    tools.forEach((tool) => {
      const li = document.createElement("li");
      const card = document.createElement("button");
      card.style.display = "block";
      card.style.width = "100%";
      card.style.padding = "1.5rem";
      card.style.backgroundColor = tool.isBack ? "#1e293b" : "#0284c7";
      card.style.color = "#e2e8f0";
      card.style.border = "1px solid #334155";
      card.style.borderRadius = "8px";
      card.style.cursor = "pointer";
      card.style.textAlign = "left";
      card.style.transition = "all 0.2s ease";

      card.onmouseenter = () => {
        card.style.transform = "translateY(-2px)";
        card.style.boxShadow = "0 10px 15px -3px rgba(0, 0, 0, 0.3)";
        card.style.borderColor = "#38bdf8";
      };
      card.onmouseleave = () => {
        card.style.transform = "translateY(0)";
        card.style.boxShadow = "none";
        card.style.borderColor = "#334155";
      };

      card.onclick = () => {
        if (tool.isLink && tool.url) {
          window.location.href = tool.url;
        } else {
          this.engine.goToScene(tool.scene);
        }
      };

      const cardTitle = document.createElement("div");
      cardTitle.textContent = tool.title;
      cardTitle.style.fontSize = "1.2rem";
      cardTitle.style.fontWeight = "bold";
      cardTitle.style.marginBottom = "0.5rem";
      card.appendChild(cardTitle);

      const cardDesc = document.createElement("div");
      cardDesc.textContent = tool.desc;
      cardDesc.style.fontSize = "0.9rem";
      cardDesc.style.color = "#94a3b8";
      card.appendChild(cardDesc);

      li.appendChild(card);
      list.appendChild(li);
    });

    container.appendChild(list);
    document.body.appendChild(container);
    this.overlay = container;
  }

  private removeUI() {
    if (this.overlay && this.overlay.parentNode) {
      this.overlay.parentNode.removeChild(this.overlay);
    }
    this.overlay = null;
  }
}
