import { SPRITE_BASE_DIR, TARGET_FRAME_MS } from "./types";

export class VocalPortraitManager {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private spriteImg: HTMLImageElement;
  private spriteAnimId = 0;
  private spriteCols = 8;
  private cellWidth = 0;
  private cellHeight = 0;

  public selectedRow = 0;
  public selectedCol = 0;
  public activeState = "BGM";
  private lastStateCols: Record<string, number> = { BGM: 0, VOCAL: 0, CHORUS: 0, VOCAL_UP: 0 };
  private lastReselectTime = 0;
  private currentSpriteLoaded = false;
  private isTransitioning = false;
  private transSourceCell = { row: 0, col: 0 };
  private transTargetCell = { row: 0, col: 0 };
  private transStartTime = 0;
  private lastSpriteDraw = 0;

  // ゲーム内状態を参照するためのコールバック
  private getGameTime: () => number;
  private getBpm: () => number;
  private isGamePlaying: () => boolean;
  private getSingingData: () => {
    singing: [number, number][];
    excited: [number, number][];
    chorus: [number, number][];
  };

  constructor(
    canvas: HTMLCanvasElement,
    getGameTime: () => number,
    getBpm: () => number,
    isGamePlaying: () => boolean,
    getSingingData: () => {
      singing: [number, number][];
      excited: [number, number][];
      chorus: [number, number][];
    },
  ) {
    this.canvas = canvas;
    const context = canvas.getContext("2d");
    if (!context) throw new Error("Could not get 2D context");
    this.ctx = context;
    this.spriteImg = new Image();
    this.getGameTime = getGameTime;
    this.getBpm = getBpm;
    this.isGamePlaying = isGamePlaying;
    this.getSingingData = getSingingData;
  }

  public loadPortraitSprite(attr: string, emotion: string): void {
    cancelAnimationFrame(this.spriteAnimId);
    this.currentSpriteLoaded = false;
    this.spriteImg = new Image();
    this.spriteImg.onload = () => {
      this.currentSpriteLoaded = true;
      this.canvas.width = 360;
      this.canvas.height = 398;
      this.spriteCols = 8;
      this.cellWidth = this.spriteImg.width / 8;
      this.cellHeight = this.spriteImg.height / 4;
      this.selectedRow = 0;
      this.selectedCol = 0;
      this.activeState = "BGM";
      this.lastReselectTime = Date.now();
      this.drawSpriteFrame();
    };
    this.spriteImg.onerror = () => {
      if (attr !== "elegant" || emotion !== "neutral") {
        this.loadPortraitSprite("elegant", "neutral");
      }
    };
    this.spriteImg.src = `${SPRITE_BASE_DIR}vocal_sprite_${attr}_${emotion}_8x4.webp`;
  }

  public getRawStateAtTime(time: number): string {
    if (!this.isGamePlaying()) return "BGM";
    const data = this.getSingingData();
    const isSinging = data.singing.some((r) => time >= r[0] && time <= r[1]);
    const isExcited = data.excited.some((r) => time >= r[0] && time <= r[1]);
    const isChorus = data.chorus.some((r) => time >= r[0] && time <= r[1]);
    if (isSinging && isExcited) return "VOCAL_UP";
    if (isSinging) return "VOCAL";
    if (isChorus) return "CHORUS";
    return "BGM";
  }

  private triggerRandomCellForState(state: string) {
    const rowMap: Record<string, number> = { BGM: 0, VOCAL: 1, CHORUS: 2, VOCAL_UP: 3 };
    const row = rowMap[state] || 0;
    let col = Math.floor(Math.random() * this.spriteCols);
    const prev = this.lastStateCols[state];
    for (let i = 0; (col === this.selectedCol || col === prev) && i < 10; i++) {
      col = Math.floor(Math.random() * this.spriteCols);
    }
    this.lastStateCols[state] = col;
    this.startSpriteTransition(row, col);
    this.lastReselectTime = Date.now();
  }

  private startSpriteTransition(row: number, col: number) {
    if (row === this.selectedRow && col === this.selectedCol) return;
    this.transSourceCell = { row: this.selectedRow, col: this.selectedCol };
    this.transTargetCell = { row, col };
    this.transStartTime = Date.now();
    this.isTransitioning = true;
  }

  private drawSpriteCell(
    cell: { row: number; col: number },
    alpha: number,
    xOffset = 0,
    scaleMultiplier = 1.0,
  ) {
    const cw = this.canvas.width;
    const ch = this.canvas.height;
    const sx = cell.col * this.cellWidth;
    const sy = cell.row * this.cellHeight;
    const aspect = this.cellWidth / this.cellHeight;
    let dw = cw * 1.16;
    let dh = ch * 1.16;
    if (cw / ch > aspect) dw = ch * aspect * 1.16;
    else dh = (cw / aspect) * 1.16;

    let scale = 1;
    let yOffset = 0;
    if (this.isGamePlaying()) {
      const bpm = this.getBpm();
      const gameTime = this.getGameTime();
      const beat = (gameTime / (60 / bpm)) % 1;
      const vocalBoost = this.activeState === "VOCAL" || this.activeState === "VOCAL_UP" ? 1 : 0.38;
      scale = 1 + 0.035 * vocalBoost * Math.exp(-beat * 8);
      yOffset = dh * 0.018 * vocalBoost * Math.sin(beat * Math.PI);
    }

    dw *= scale * scaleMultiplier;
    dh *= scale * scaleMultiplier;
    const dx = (cw - dw) / 2 + xOffset;
    const dy = (ch - dh) / 2 + yOffset;

    this.ctx.save();
    this.ctx.globalAlpha = alpha;
    this.ctx.imageSmoothingEnabled = true;
    this.ctx.drawImage(this.spriteImg, sx, sy, this.cellWidth, this.cellHeight, dx, dy, dw, dh);
    this.ctx.restore();
  }

  public drawSpriteFrame(): void {
    if (!this.currentSpriteLoaded || !this.spriteImg.complete) return;
    const frameNow = performance.now();
    if (frameNow - this.lastSpriteDraw < TARGET_FRAME_MS) {
      this.spriteAnimId = requestAnimationFrame(() => this.drawSpriteFrame());
      return;
    }
    this.lastSpriteDraw = frameNow;
    const cw = this.canvas.width;
    const ch = this.canvas.height;
    this.ctx.clearRect(0, 0, cw, ch);
    this.ctx.fillStyle = "#f4ecd8";
    this.ctx.fillRect(0, 0, cw, ch);

    const now = Date.now();
    const gameTime = this.getGameTime();
    const targetState = this.getRawStateAtTime(gameTime || 0);
    if (targetState !== this.activeState) {
      this.activeState = targetState;
      this.triggerRandomCellForState(this.activeState);
    }

    const bpm = this.getBpm();
    const t = Math.min(1, Math.max(0, (bpm - 80) / 50));
    const intervalMs = (5 - 2 * t) * 1000;
    if (
      this.isGamePlaying() &&
      !this.isTransitioning &&
      now - this.lastReselectTime >= intervalMs
    ) {
      this.triggerRandomCellForState(this.activeState);
    }

    if (this.isTransitioning) {
      const progress = Math.min(1, (now - this.transStartTime) / 220); // 220msに少し滑らかに調整

      // スライド幅を120pxに抑え、中央で綺麗にクロスフェードするように調整
      const slideWidth = 120;

      // 旧画像: 左にスライド（0 -> -slideWidth）しながらフェードアウト
      const sourceAlpha = 1 - progress;
      const sourceX = -slideWidth * progress;
      this.drawSpriteCell(this.transSourceCell, sourceAlpha, sourceX);

      // 新画像: 右からスライド（slideWidth -> 0）しながらフェードイン
      const targetAlpha = progress;
      const targetX = slideWidth - slideWidth * progress;
      this.drawSpriteCell(this.transTargetCell, targetAlpha, targetX);

      if (progress >= 1) {
        this.selectedRow = this.transTargetCell.row;
        this.selectedCol = this.transTargetCell.col;
        this.isTransitioning = false;
      }
    } else {
      this.drawSpriteCell({ row: this.selectedRow, col: this.selectedCol }, 1);
    }
    this.spriteAnimId = requestAnimationFrame(() => this.drawSpriteFrame());
  }

  public stop(): void {
    cancelAnimationFrame(this.spriteAnimId);
  }
}
