import { RhythmGameCore, RhythmCoreCallbacks } from "./core";
import { Note, ATTR, JUDGMENT_X_RATIO } from "./types";

export class BraveRhythmGameCore extends RhythmGameCore {
  public lastHitAttribute: string | null = null;
  private onLockVisualsUpdate: (lastAttr: string | null) => void;

  constructor(
    callbacks: RhythmCoreCallbacks,
    onLockVisualsUpdate: (lastAttr: string | null) => void,
  ) {
    super(callbacks);
    this.onLockVisualsUpdate = onLockVisualsUpdate;
  }

  public updateLockVisuals(): void {
    this.onLockVisualsUpdate(this.lastHitAttribute);
  }

  public resetRunStats(): void {
    super.resetRunStats();
    this.lastHitAttribute = null;
    this.updateLockVisuals();
  }

  public startGame(notes: Array<{ time: number; attribute: string }>): void {
    this.resetRunStats();

    // 勇猛独自のノーツ展開ロジック
    const expandedNotes: Note[] = [];
    let noteIdCounter = 0;
    notes.forEach((note) => {
      const originalAttr = ATTR[note.attribute] ? note.attribute : "elegant";
      const otherAttrs = ["mystic", "elegant", "brave"].filter((a) => a !== originalAttr);
      const groupId = note.time.toString();
      otherAttrs.forEach((attr) => {
        expandedNotes.push({
          id: noteIdCounter++,
          groupId: groupId,
          time: Number(note.time),
          attribute: attr,
          hit: false,
          missed: false,
          dom: null,
        });
      });
    });

    expandedNotes.sort((a, b) => a.time - b.time);
    this.currentNotes = expandedNotes;

    this.isPlaying = true;
    this.isPaused = false;
    this.isCountingDown = true;
    this.isApproaching = false;
    this.countdownStart = performance.now();
    this.lastGameLoopUpdate = 0;

    this.callbacks.pauseAudio();
    this.callbacks.setAudioTime(0);
    this.callbacks.setAudioMuted(true);
    this.callbacks.playAudio().catch(() => {});

    this.callbacks.onCountdownState("3", "active");

    // 親クラスのループ処理を起動するため、updateGameLoopは親の仕組みを利用
    // TypeScript/ES6でアロー関数内のthisコンテキスト維持のため、バインドして起動

    // 親の仕組みに任せるために、一旦親クラスの startGame を呼び出した後に、
    // 勇猛用に currentNotes を差し替えるようにオーバーライドするのが最も安全です。

    // （修正）親クラスの startGame を利用した実装
  }

  // startGameの親呼び出しによるオーバーライド
  public startGameDirect(notes: Array<{ time: number; attribute: string }>): void {
    super.startGame(notes);

    // 親のstartGameが呼んだあとに、currentNotesを勇猛用に再構築
    const expandedNotes: Note[] = [];
    let noteIdCounter = 0;
    notes.forEach((note) => {
      const originalAttr = ATTR[note.attribute] ? note.attribute : "elegant";
      const otherAttrs = ["mystic", "elegant", "brave"].filter((a) => a !== originalAttr);
      const groupId = note.time.toString();
      otherAttrs.forEach((attr) => {
        expandedNotes.push({
          id: noteIdCounter++,
          groupId: groupId,
          time: Number(note.time),
          attribute: attr,
          hit: false,
          missed: false,
          dom: null,
        });
      });
    });
    expandedNotes.sort((a, b) => a.time - b.time);
    this.currentNotes = expandedNotes;

    this.lastHitAttribute = null;
    this.updateLockVisuals();
  }

  public judgeInput(
    attribute: string,
    isRelease = false,
    containerWidth: number,
    containerHeight: number,
    activeState: string,
  ): void {
    if (!this.isPlaying || this.isPaused || this.isCountingDown || this.gameTime < 0) return;

    // 勇猛独自の同レーンペナルティチェック (直前の属性と同じならペナルティ)
    if (!isRelease && this.lastHitAttribute === attribute) {
      this.score = Math.max(0, this.score - 50);
      this.combo = 0;
      this.callbacks.updateJudgeMeter(1, "#f87171", "LOCKED!");
      this.updateHUD();

      // 最も近いノーツを消す
      const now = this.getAdjustedGameTime();
      const windowSec = this.callbacks.getWindowSec();
      let closest: Note | null = null;
      let closestDiff = Infinity;
      for (const note of this.currentNotes) {
        if (note.missed || note.attribute !== attribute || note.hit) continue;
        const abs = Math.abs(note.time - now);
        if (abs <= windowSec && abs < closestDiff) {
          closest = note;
          closestDiff = abs;
        }
      }
      if (closest) {
        closest.missed = true;
        if (closest.dom) closest.dom.remove();
      }

      const x = containerWidth * JUDGMENT_X_RATIO;
      const y = this.laneY(attribute, containerHeight);
      this.callbacks.burstAt(x, y, "#f87171", this.combo);
      this.callbacks.showHitText("LOCKED!", "#f87171", y);
      return;
    }

    // ペナルティチェックをパスしたら、親の判定ロジックを実行する前に、
    // どのノーツがヒットするかを仮判定し、排他処理を行う。
    // 親の judgeInput 内で closest.hit = true がセットされるため、
    // 同グループのもう一方のノーツを消す処理を仕込む。
    const now = this.getAdjustedGameTime();
    const windowSec = this.callbacks.getWindowSec();
    let closest: Note | null = null;
    let closestDiff = Infinity;

    for (const note of this.currentNotes) {
      if (note.missed || note.attribute !== attribute) continue;
      if (isRelease && note.released) continue;
      if (!isRelease && note.hit) continue;
      const abs = Math.abs(note.time - now);
      if (abs <= windowSec && abs < closestDiff) {
        closest = note;
        closestDiff = abs;
      }
    }

    if (closest) {
      // --- 勇猛: 排他処理 (同じグループのもう一方を消す) ---
      for (const note of this.currentNotes) {
        if (note.groupId === closest.groupId && note.id !== closest.id) {
          note.missed = true;
          if (note.dom) note.dom.remove();
        }
      }
    }

    // 親クラスの判定処理を実行
    super.judgeInput(attribute, isRelease, containerWidth, containerHeight, activeState);

    // 判定が正常に行われたら、lastHitAttributeを更新
    // （ヒット時もしくはリリース時、親クラスの判定結果が反映された後）
    if (closest && (closest.hit || closest.released)) {
      this.lastHitAttribute = attribute;
      this.updateLockVisuals();
    }
  }
}
