/*
仕様:
  最小タイトルScene。

役割:
  - 起動確認用のテキストを表示する。
  - Excalibur描画が動作していることを目視確認できるようにする。

更新時の注意:
  本格的なタイトルUIはui/またはscene専用ファイルへ分離する。
*/
import * as ex from 'excalibur';

export class TitleScene extends ex.Scene {
  override onInitialize(engine: ex.Engine): void {
    const label = new ex.Label({
      text: 'Excalibur Template 起動確認',
      x: engine.drawWidth / 2,
      y: engine.drawHeight / 2,
      font: new ex.Font({ size: 48, family: 'sans-serif', textAlign: ex.TextAlign.Center })
    });
    this.add(label);
  }
}
