/*
仕様:
  Excalibur Engineの生成と初期Scene登録を行う。

役割:
  - FHD基準のEngineを作る。
  - TitleSceneを登録して開始する。
  - ?debug=true クエリパラメータがあればDebugHubSceneを起動する。

更新時の注意:
  ゲームルール本体はlogic配下へ分離する。
*/
import * as ex from 'excalibur';
import { DISPLAY } from './config/display';
import { TitleScene } from './scenes/TitleScene';
import { DebugHubScene } from './scenes/DebugHubScene';
import { RhythmTesterScene } from '../devtools/rhythm-tester-ex';

export function createGameApp(): ex.Engine {
  const engine = new ex.Engine({
    width: DISPLAY.width,
    height: DISPLAY.height,
    canvasElementId: DISPLAY.canvasId,
    displayMode: ex.DisplayMode.Fixed,
    backgroundColor: ex.Color.fromHex(DISPLAY.backgroundColor)
  });
  engine.add('title', new TitleScene());
  engine.add('debug-hub', new DebugHubScene());
  engine.add('elegant-rhythm-tester', new RhythmTesterScene('elegant'));
  engine.add('brave-rhythm-tester', new RhythmTesterScene('brave'));

  const params = new URLSearchParams(window.location.search);
  if (params.get('debug') === 'true') {
    engine.goToScene('debug-hub');
  } else {
    engine.goToScene('title');
  }
  return engine;
}

