export interface VisualizerParticle {
  x: number;
  y: number;
  type: "ring" | "bubble" | "text";
  color: string;
  alpha: number;
  decay: number;
  size: number;
  targetSize?: number;
  vx?: number;
  vy?: number;
  char?: string;
  rot?: number;
  vrot?: number;
}

export function appendSparkParticles(
  particles: VisualizerParticle[],
  x: number,
  y: number,
  color: string,
): void {
  particles.push({
    x,
    y,
    type: "ring",
    color,
    alpha: 1,
    decay: 0.05,
    size: 10,
    targetSize: 80,
  });

  for (let i = 0; i < 8; i++) {
    const angle = Math.PI * 2 * (i / 8) + Math.random() * 0.22;
    const dist = 30 + Math.random() * 74;
    const speed = dist / 0.5;
    particles.push({
      x,
      y,
      type: "text",
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      color,
      alpha: 1,
      decay: 0.03,
      size: 6 + Math.random() * 8,
      char: ["✦", "＊", "✧"][Math.floor(Math.random() * 3)],
      rot: Math.random() * 360,
      vrot: (Math.random() - 0.5) * 10,
    });
  }
}

export function appendCompanionParticles(
  particles: VisualizerParticle[],
  x: number,
  y: number,
  color: string,
  char: string = "",
  strong: boolean = false,
): void {
  // '?' または '??' の場合は音符や星マークなどの華やかな文字に置き換える
  let displayChar = char;
  if (char === "?" || char === "??" || !char) {
    displayChar = ["♪", "♫", "★", "✦", "✧"][Math.floor(Math.random() * 5)];
  } else if (char.length > 1) {
    displayChar = char[Math.floor(Math.random() * char.length)];
  }

  const count = strong ? 12 : 6;
  const baseAngle = -Math.PI / 2;
  // 範囲をより大胆にするため、角度の広がり（spread）を 120度から 160度に広げ、速度もアップ
  const spread = (160 * Math.PI) / 180;
  const lift = strong ? 280 : 180;

  for (let i = 0; i < count; i++) {
    const angle = baseAngle + (Math.random() - 0.5) * spread;
    const dist = lift * (0.5 + Math.random() * 0.8);
    const speed = dist / 0.8;

    // 色に変化を加えて散らす（HSLに変換して色相をずらす、または微細なランダム変化）
    // 元のカラーのRGB値を解析して若干のバリエーションを持たせる
    let finalColor = color;
    if (color.startsWith("#")) {
      const r = parseInt(color.slice(1, 3), 16);
      const g = parseInt(color.slice(3, 5), 16);
      const b = parseInt(color.slice(5, 7), 16);
      // 色相や明るさをランダムに少しずらす
      const dr = Math.floor((Math.random() - 0.5) * 60);
      const dg = Math.floor((Math.random() - 0.5) * 60);
      const db = Math.floor((Math.random() - 0.5) * 60);
      const nr = Math.max(0, Math.min(255, r + dr));
      const ng = Math.max(0, Math.min(255, g + dg));
      const nb = Math.max(0, Math.min(255, b + db));
      finalColor = `rgb(${nr}, ${ng}, ${nb})`;
    }

    particles.push({
      x: x + (Math.random() - 0.5) * 50,
      y: y + (Math.random() - 0.5) * 30,
      type: "text",
      vx: Math.cos(angle) * speed + (Math.random() - 0.5) * 80,
      vy: Math.sin(angle) * speed - Math.random() * 40, // 上方向への勢いを強める
      color: finalColor,
      alpha: 1,
      decay: strong ? 0.01 : 0.014, // 寿命を少し伸ばして華やかさを維持
      size: (strong ? 32 : 24) + Math.random() * 10,
      char:
        displayChar === "random"
          ? ["♪", "♫", "★", "✦", "✧"][Math.floor(Math.random() * 5)]
          : displayChar,
      rot: Math.random() * 360,
      vrot: (Math.random() - 0.5) * 8,
    });
  }
}
