import { DEFAULT_BINDINGS, KEY_LABELS, SETTINGS_STORAGE_KEY, BindingConfig } from "./types";

export class RhythmInputManager {
  public keyBindings: Record<string, BindingConfig> = JSON.parse(JSON.stringify(DEFAULT_BINDINGS));
  public keyJudgeTiming = "down";
  public waitingBindAttr = "";
  public inputMode = "mouse";

  // コールバック
  private onJudgeInput: (attribute: string, isRelease: boolean) => void;
  private isModalActive: () => boolean;

  constructor(
    onJudgeInput: (attribute: string, isRelease: boolean) => void,
    isModalActive: () => boolean,
  ) {
    this.onJudgeInput = onJudgeInput;
    this.isModalActive = isModalActive;
  }

  public getAttributeForKey(code: string): string {
    for (const attr of Object.keys(this.keyBindings)) {
      if (this.keyBindings[attr].key === code) return attr;
    }
    return "";
  }

  public getAttributeForMouse(btn: number): string {
    for (const attr of Object.keys(this.keyBindings)) {
      if (this.keyBindings[attr].mouse === String(btn)) return attr;
    }
    return "";
  }

  public isTextEntryTarget(target: EventTarget | null): boolean {
    if (!(target instanceof HTMLElement)) return false;
    if (target.isContentEditable) return true;
    return target.matches("input, textarea, select");
  }

  public blurFocusedActionForGameKey(code: string): void {
    if (code !== "Space" && code !== "Enter") return;
    const active = document.activeElement;
    if (!(active instanceof HTMLElement)) return;
    if (active.matches("button, a, [role='button'], input[type='button'], input[type='submit']")) {
      active.blur();
    }
  }

  public isKeyboardInputBlocked(target: EventTarget | null): boolean {
    if (this.isModalActive()) return true;
    return this.isTextEntryTarget(target);
  }

  public setKeyBinding(attr: string, code: string): void {
    for (const k of Object.keys(this.keyBindings)) {
      if (k !== attr && this.keyBindings[k].key === code) this.keyBindings[k].key = "";
    }
    this.keyBindings[attr].key = code;
    this.waitingBindAttr = "";
    document.querySelectorAll(".bind-key-btn").forEach((btn) => btn.classList.remove("waiting"));
    if (document.activeElement instanceof HTMLElement) document.activeElement.blur();
    this.saveSettings();
    this.refreshBindingUI();
  }

  public setMouseBinding(attr: string, buttonValue: string): void {
    for (const k of Object.keys(this.keyBindings)) {
      if (k !== attr && this.keyBindings[k].mouse === buttonValue && buttonValue !== "none") {
        this.keyBindings[k].mouse = "none";
      }
    }
    this.keyBindings[attr].mouse = buttonValue;
    this.saveSettings();
    this.refreshBindingUI();
  }

  public isTouchDevice(): boolean {
    const mobileUA = /Android|iPhone|iPad|iPod|Mobile|Windows Phone/i.test(navigator.userAgent);
    const compactTouch =
      navigator.maxTouchPoints > 0 &&
      window.matchMedia("(pointer: coarse)").matches &&
      Math.min(window.innerWidth, window.innerHeight) <= 820;
    return mobileUA || compactTouch;
  }

  public refreshBindingUI(): void {
    for (const attr of Object.keys(this.keyBindings)) {
      const keyBtn = document.querySelector(`[data-key-bind="${attr}"]`);
      const mouseSelect = document.querySelector(
        `[data-mouse-bind="${attr}"]`,
      ) as HTMLSelectElement | null;
      if (keyBtn) {
        const code = this.keyBindings[attr].key;
        keyBtn.textContent = KEY_LABELS[code] || code.replace(/^Key/, "") || "未設定";
      }
      if (mouseSelect) mouseSelect.value = this.keyBindings[attr].mouse;
    }
  }

  public readSavedSettings(): Record<string, unknown> {
    try {
      return JSON.parse(localStorage.getItem(SETTINGS_STORAGE_KEY) || "{}") as Record<string, unknown>;
    } catch {
      return {};
    }
  }

  public normalizeBindings(raw: Record<string, unknown> | null | undefined): Record<string, BindingConfig> {
    const next = JSON.parse(JSON.stringify(DEFAULT_BINDINGS)) as Record<string, BindingConfig>;
    for (const attr of Object.keys(next)) {
      if (!raw) continue;
      const val = raw[attr];
      if (!val || typeof val !== "object") continue;
      const obj = val as Record<string, unknown>;
      if (typeof obj.key === "string" && obj.key) next[attr].key = obj.key;
      if (typeof obj.mouse === "string") next[attr].mouse = obj.mouse;
    }
    return next;
  }

  public applySavedSettings(selectors: {
    densitySelect: HTMLSelectElement;
    windowSelect: HTMLSelectElement;
    speedInput: HTMLInputElement;
    bgmVol: HTMLInputElement;
    companionCountSelect: HTMLSelectElement;
    audienceCountSelect: HTMLSelectElement;
    keyTimingSelect: HTMLSelectElement;
    noteSpeedRef: { val: number };
    playerRef: HTMLAudioElement;
  }): void {
    const settings = this.readSavedSettings();
    if (typeof settings.density === "string") selectors.densitySelect.value = settings.density;
    if (typeof settings.window === "string") selectors.windowSelect.value = settings.window;
    if (typeof settings.speed === "string") {
      selectors.speedInput.value = settings.speed;
      selectors.noteSpeedRef.val = Number(settings.speed);
    }
    if (typeof settings.offset === "string") {
      const offsetEl = document.getElementById("offset") as HTMLInputElement | null;
      if (offsetEl) offsetEl.value = settings.offset;
    }
    if (typeof settings.bgm === "string") {
      selectors.bgmVol.value = settings.bgm;
      selectors.playerRef.volume = Number(settings.bgm) / 100;
    }
    if (typeof settings.companionCount === "string")
      selectors.companionCountSelect.value = settings.companionCount;
    if (typeof settings.audienceCount === "string")
      selectors.audienceCountSelect.value = settings.audienceCount;
    this.keyJudgeTiming = settings.keyJudgeTiming === "up" ? "up" : "down";
    selectors.keyTimingSelect.value = this.keyJudgeTiming;
    this.keyBindings = this.normalizeBindings(settings.bindings as Record<string, unknown> | undefined);
  }

  public saveSettings(extraSettings?: Record<string, unknown>): void {
    const trackSelect = document.getElementById("track-select") as HTMLSelectElement | null;
    const densitySelect = document.getElementById("density-select") as HTMLSelectElement | null;
    const windowSelect = document.getElementById("window-select") as HTMLSelectElement | null;
    const speedInput = document.getElementById("note-speed-input") as HTMLInputElement | null;
    const offsetInput = document.getElementById("offset") as HTMLInputElement | null;
    const bgmVol = document.getElementById("bgm-vol") as HTMLInputElement | null;
    const companionCountSelect = document.getElementById(
      "companion-count-select",
    ) as HTMLSelectElement | null;
    const audienceCountSelect = document.getElementById(
      "audience-count-select",
    ) as HTMLSelectElement | null;

    const settings = {
      track: trackSelect?.value || "0",
      density: densitySelect?.value || "2",
      window: windowSelect?.value || "150",
      speed: speedInput?.value || "180",
      offset: offsetInput?.value || "0",
      bgm: bgmVol?.value || "80",
      keyJudgeTiming: this.keyJudgeTiming,
      bindings: this.keyBindings,
      companionCount: companionCountSelect?.value || "3",
      audienceCount: audienceCountSelect?.value || "50",
      ...extraSettings,
    };
    localStorage.setItem(SETTINGS_STORAGE_KEY, JSON.stringify(settings));
  }

  public syncControlLabels(): void {
    const speedInput = document.getElementById("note-speed-input") as HTMLInputElement | null;
    const speedVal = document.getElementById("speed-val");
    const offsetInput = document.getElementById("offset") as HTMLInputElement | null;
    const offsetVal = document.getElementById("offset-val");
    const bgmVol = document.getElementById("bgm-vol") as HTMLInputElement | null;
    const bgmVolVal = document.getElementById("bgm-vol-val");
    const seVol = document.getElementById("se-vol") as HTMLInputElement | null;
    const seVolVal = document.getElementById("se-vol-val");

    if (speedInput && speedVal) {
      speedVal.textContent = `${speedInput.value} px/s`;
    }
    if (offsetInput && offsetVal) {
      const val = Number(offsetInput.value);
      offsetVal.textContent = `${val > 0 ? "+" : ""}${val} ms`;
    }
    if (bgmVol && bgmVolVal) {
      bgmVolVal.textContent = `${bgmVol.value}%`;
    }
    if (seVol && seVolVal) {
      seVolVal.textContent = seVol.value === "0" ? "OFF" : `${seVol.value}%`;
    }
  }

  public setInputMode(mode: string): void {
    this.inputMode = mode;
    const inputModeSelect = document.getElementById(
      "input-mode-select",
    ) as HTMLSelectElement | null;
    const inputModeStatus = document.getElementById("input-mode-status");

    if (inputModeSelect) inputModeSelect.value = mode;
    document.body.dataset.inputMode = mode;
    if (inputModeStatus) {
      const strong = inputModeStatus.querySelector("strong");
      const span = inputModeStatus.querySelector("span");
      if (strong) strong.textContent = mode === "touch" ? "TOUCH" : "PC";
      if (span) span.textContent = mode === "touch" ? "LANE" : "KEY+MOUSE";
    }
  }

  public updateInputModeFromDevice(): void {
    this.setInputMode(this.isTouchDevice() ? "touch" : "mouse");
  }

  public setupEventListeners(isMouseInputBlocked: (target: EventTarget | null) => boolean): void {
    // タッチレーン操作
    document.querySelectorAll(".touch-lane-hitarea").forEach((lane) => {
      const htmlLane = lane as HTMLElement;
      lane.addEventListener("pointerdown", (e: Event) => {
        const pe = e as PointerEvent;
        if (pe.pointerType === "mouse") return;
        if (this.inputMode !== "touch") return;
        pe.preventDefault();
        pe.stopPropagation();
        if (htmlLane.dataset.attr) this.onJudgeInput(htmlLane.dataset.attr, false);
      });
      lane.addEventListener("pointerup", (e: Event) => {
        const pe = e as PointerEvent;
        if (pe.pointerType === "mouse") return;
        if (this.inputMode !== "touch") return;
        pe.preventDefault();
        pe.stopPropagation();
        if (htmlLane.dataset.attr) this.onJudgeInput(htmlLane.dataset.attr, true);
      });
      lane.addEventListener("contextmenu", (e) => {
        e.preventDefault();
        e.stopPropagation();
      });
    });

    document.querySelectorAll(".input-btn").forEach((btn) => {
      const htmlBtn = btn as HTMLElement;
      btn.addEventListener("pointerdown", (e: Event) => {
        const pe = e as PointerEvent;
        if (pe.pointerType === "mouse") return;
        pe.preventDefault();
        pe.stopPropagation();
        if (this.inputMode === "touch" && htmlBtn.dataset.attr) {
          this.onJudgeInput(htmlBtn.dataset.attr, false);
        }
      });
      btn.addEventListener("pointerup", (e: Event) => {
        const pe = e as PointerEvent;
        if (pe.pointerType === "mouse") return;
        pe.preventDefault();
        pe.stopPropagation();
        if (this.inputMode === "touch" && htmlBtn.dataset.attr) {
          this.onJudgeInput(htmlBtn.dataset.attr, true);
        }
      });
      btn.addEventListener("contextmenu", (e) => {
        e.preventDefault();
        e.stopPropagation();
      });
    });

    // マウス打鍵操作
    document.addEventListener(
      "mousedown",
      (e) => {
        if (this.inputMode !== "mouse") return;
        if (isMouseInputBlocked(e.target)) return;
        const attr = this.getAttributeForMouse(e.button);
        if (attr) {
          e.preventDefault();
          this.onJudgeInput(attr, false);
        }
      },
      true,
    ); // useCapture = true (make_brave.cjs で useCapture に置換される対策)

    document.addEventListener(
      "mouseup",
      (e) => {
        if (this.inputMode !== "mouse") return;
        if (isMouseInputBlocked(e.target)) return;
        const attr = this.getAttributeForMouse(e.button);
        if (attr) {
          e.preventDefault();
          this.onJudgeInput(attr, true);
        }
      },
      true,
    );

    document.addEventListener("contextmenu", (e) => {
      if (this.inputMode === "mouse" && !isMouseInputBlocked(e.target)) {
        e.preventDefault();
      }
    });

    document.addEventListener("click", (e) => {
      if (e.target instanceof Element) {
        const btn = e.target.closest("button, a");
        if (btn && btn instanceof HTMLElement) {
          btn.blur();
        }
      }
    });

    document.addEventListener("change", (e) => {
      if (e.target instanceof HTMLElement) {
        e.target.blur();
      }
    });

    // キーボード打鍵操作
    document.addEventListener("keydown", (e) => {
      if (e.repeat) return;
      if (this.waitingBindAttr) {
        e.preventDefault();
        e.stopPropagation();
        if (e.code !== "Escape") {
          this.setKeyBinding(this.waitingBindAttr, e.code);
        } else {
          this.waitingBindAttr = "";
          this.refreshBindingUI();
        }
        return;
      }
      if (e.key === "Escape") {
        const configModal = document.getElementById("config-modal");
        if (configModal && configModal.classList.contains("active")) {
          configModal.classList.remove("active");
          return;
        }
        // ESCでの一時停止のトリガーはCore側で処理するためここでは何もしない
        return;
      }
      if (this.inputMode !== "mouse") return;
      const attr = this.getAttributeForKey(e.code);
      if (attr) {
        e.preventDefault();
        e.stopPropagation();
        this.blurFocusedActionForGameKey(e.code);
        if (this.isKeyboardInputBlocked(e.target)) return;
        this.onJudgeInput(attr, false);
      }
    });

    document.addEventListener("keyup", (e) => {
      if (this.inputMode !== "mouse") return;
      const attr = this.getAttributeForKey(e.code);
      if (!attr) return;
      e.preventDefault();
      e.stopPropagation();
      this.blurFocusedActionForGameKey(e.code);
      if (this.isKeyboardInputBlocked(e.target)) return;
      this.onJudgeInput(attr, true);
    });
  }
}
